# Unit Tests for `binary_search`

```python
import pytest
from binary_search import binary_search


# ---------------------------------------------------------------------------
# Happy path tests
# ---------------------------------------------------------------------------

class TestHappyPath:
    def test_target_in_middle(self):
        assert binary_search([1, 3, 5, 7, 9], 5) == 2

    def test_target_at_beginning(self):
        assert binary_search([1, 3, 5, 7, 9], 1) == 0

    def test_target_at_end(self):
        assert binary_search([1, 3, 5, 7, 9], 9) == 4

    def test_single_element_found(self):
        assert binary_search([42], 42) == 0

    def test_two_elements_first(self):
        assert binary_search([10, 20], 10) == 0

    def test_two_elements_second(self):
        assert binary_search([10, 20], 20) == 1

    def test_large_sorted_array(self):
        arr = list(range(0, 1000, 2))   # [0, 2, 4, ..., 998]
        assert binary_search(arr, 500) == 250

    def test_negative_numbers(self):
        arr = [-10, -7, -3, -1, 0]
        assert binary_search(arr, -7) == 1

    def test_mixed_negative_and_positive(self):
        arr = [-5, -3, 0, 4, 8]
        assert binary_search(arr, 0) == 2

    def test_returns_correct_index_not_just_truthy(self):
        # Index 0 is falsy; make sure we get 0, not just a truthy/falsy check
        arr = [1, 2, 3]
        result = binary_search(arr, 1)
        assert result == 0
        assert result is not False


# ---------------------------------------------------------------------------
# Edge case tests
# ---------------------------------------------------------------------------

class TestEdgeCases:
    def test_empty_array_returns_minus_one(self):
        assert binary_search([], 5) == -1

    def test_single_element_not_found(self):
        assert binary_search([7], 3) == -1

    def test_target_smaller_than_all_elements(self):
        assert binary_search([10, 20, 30], 5) == -1

    def test_target_larger_than_all_elements(self):
        assert binary_search([10, 20, 30], 99) == -1

    def test_target_between_elements_not_present(self):
        assert binary_search([1, 3, 5, 7], 4) == -1

    def test_duplicate_values_returns_a_valid_index(self):
        # The function is not required to return a specific duplicate index,
        # only a valid one.
        arr = [2, 2, 2, 2, 2]
        result = binary_search(arr, 2)
        assert result in range(len(arr))
        assert arr[result] == 2

    def test_two_elements_target_not_present(self):
        assert binary_search([1, 3], 2) == -1

    def test_large_values(self):
        arr = [10**9 - 2, 10**9 - 1, 10**9]
        assert binary_search(arr, 10**9) == 2

    def test_negative_target_not_in_array(self):
        arr = [-5, -3, -1, 1, 3]
        assert binary_search(arr, -4) == -1


# ---------------------------------------------------------------------------
# Return-value contract tests
# ---------------------------------------------------------------------------

class TestReturnValueContract:
    def test_returns_int_when_found(self):
        result = binary_search([1, 2, 3], 2)
        assert isinstance(result, int)
